 20â†’// TestHealth_Degraded verifies that the handler returns HTTP 503 and a
 21â†’// "degraded" JSON body when the database pool cannot be pinged.
 22â†’// A pool configured with an unreachable address (port 1 gives ECONNREFUSED
 23â†’// immediately) is used so the test runs without a live database.
 24â†’func TestHealth_Degraded(t *testing.T) {
 25â†’	t.Parallel()
 26â†’	cfg, err := pgxpool.ParseConfig("postgres://u:p@127.0.0.1:1/db?sslmode=disable&connect_timeout=1")
 27â†’	if err != nil {
 28â†’		t.Fatalf("ParseConfig: %v", err)
 29â†’	}
 30â†’	pool, err := pgxpool.NewWithConfig(context.Background(), cfg)
 31â†’	if err != nil {
 32â†’		t.Fatalf("NewWithConfig: %v", err)
 33â†’	}
 34â†’	defer pool.Close()
 35â†’
 36â†’	w := httptest.NewRecorder()
 37â†’	r := httptest.NewRequest(http.MethodGet, "/private/healthcheck", nil)
 38â†’	handler.Health(pool)(w, r)
 39â†’
 40â†’	if w.Code != http.StatusServiceUnavailable {
 41â†’		t.Errorf("HTTP status: got %d, want %d", w.Code, http.StatusServiceUnavailable)
 42â†’	}
 43â†’
 44â†’	var body struct {
 45â†’		Status string `json:"status"`
 46â†’		DB     struct {
 47â†’			Status string `json:"status"`
 48â†’		} `json:"db"`
 49â†’	}
 50â†’	if err := json.NewDecoder(w.Body).Decode(&body); err != nil {
 51â†’		t.Fatalf("decode body: %v", err)
 52â†’	}
 53â†’	if body.Status != "degraded" {
 54â†’		t.Errorf("status: got %q, want %q", body.Status, "degraded")
 55â†’	}
 56â†’	if body.DB.Status != "error" {
 57â†’		t.Errorf("db.status: got %q, want %q", body.DB.Status, "error")
 58â†’	}
 59â†’}
 60â†’
