 65â†’// TestHealth_OK verifies the healthcheck endpoint returns HTTP 200 and a valid
 66â†’// JSON body when the database is reachable. It uses a containerised PostgreSQL
 67â†’// database via testdb.New (or TEST_DATABASE_URL if set). The test is skipped
 68â†’// automatically when run with -short.
 69â†’func TestHealth_OK(t *testing.T) {
 70â†’	pool := testdb.New(t)
 71â†’
 72â†’	w := httptest.NewRecorder()
 73â†’	r := httptest.NewRequest(http.MethodGet, "/private/healthcheck", nil)
 74â†’	handler.Health(pool)(w, r)
 75â†’
 76â†’	if w.Code != http.StatusOK {
 77â†’		t.Errorf("HTTP status: got %d, want %d", w.Code, http.StatusOK)
 78â†’	}
 79â†’
 80â†’	var body struct {
 81â†’		Status  string `json:"status"`
 82â†’		Version string `json:"version"`
 83â†’		DB      struct {
 84â†’			Status    string `json:"status"`
 85â†’			LatencyMs int64  `json:"latency_ms"`
 86â†’		} `json:"db"`
 87â†’	}
 88â†’	if err := json.NewDecoder(w.Body).Decode(&body); err != nil {
 89â†’		t.Fatalf("decode body: %v", err)
 90â†’	}
 91â†’	t.Logf("healthcheck response: status=%s version=%s db.status=%s db.latency_ms=%d",
 92â†’		body.Status, body.Version, body.DB.Status, body.DB.LatencyMs)
 93â†’
 94â†’	if body.Status != "ok" {
 95â†’		t.Errorf("status: got %q, want %q", body.Status, "ok")
 96â†’	}
 97â†’	if body.DB.Status != "ok" {
 98â†’		t.Errorf("db.status: got %q, want %q", body.DB.Status, "ok")
 99â†’	}
100â†’	if body.DB.LatencyMs < 0 {
101â†’		t.Errorf("db.latency_ms should be non-negative, got %d", body.DB.LatencyMs)
102â†’	}
103â†’
104â†’	// Verify the primary search view is populated. An empty dataset_merged
105â†’	// means the application has no data to serve and should be treated as a
106â†’	// smoke-test failure.
107â†’	var count int
108â†’	if err := pool.QueryRow(context.Background(),
109â†’		"SELECT COUNT(1) FROM search_base.dataset_merged",
110â†’	).Scan(&count); err != nil {
111â†’		t.Fatalf("dataset_merged count query failed: %v", err)
112â†’	}
113â†’	t.Logf("dataset_merged row count: %d", count)
114â†’	if count == 0 {
115â†’		t.Error("dataset_merged is empty â€” no institution data available")
116â†’	}
117â†’}
