 15â†’func makeHMACToken(t *testing.T, secret string, claims Claims) string {
 16â†’	t.Helper()
 17â†’	token := jwt.NewWithClaims(jwt.SigningMethodHS256, &claims)
 18â†’	s, err := token.SignedString([]byte(secret))
 19â†’	if err != nil {
 20â†’		t.Fatalf("sign token: %v", err)
 21â†’	}
 22â†’	return s
 23â†’}
